System.register([],function(z,a){var n,t,e,s,c;return{setters:[],execute:function(){t=(z,a,n,t,e,s)=>({id:z,type:"dialogue",speaker:a,speakerKey:n,text:t,sprite:e?{key:e,position:"linmo"===e?"left":"right"}:void 0,effects:s}),e=(z,a,n)=>({id:z,type:"choice",text:a,choices:n,speaker:""}),s=(z,a,n,t,e)=>({id:z,type:"quiz",text:a,quiz:n,onCorrect:t,onWrong:e,speaker:""}),c=(z,a)=>({id:z,type:"system",text:a,speaker:""}),z("routeZhangScript",[(n=(z,a,n,t)=>({id:z,type:"narration",text:a,speaker:"",background:n,effects:t}))("zz-s1-1","张总隐藏线\n\n第5章结尾。第7次轮回。你选择了一条从未尝试过的路——在深夜的茶水间等到了张总。\n\n进入条件确认：前5位角色好感度40-60 · 答题正确率>85% · 轮回次数≥7 · 选择直接面对张总。","breakroom"),t("zz-s1-2","张总","zhang","林墨。这么晚了还不回去休息？","zhang"),,n("zz-s1-3","他的手套一如既往地戴得严严实实。但你已经知道那双手是什么样子——在第3轮回中，你无意间看到过。布满老年斑。关节变形。指甲萎缩。","breakroom"),e("zz-s1-4","你深吸一口气。这是唯一一次——你没有避开他。前6次轮回中，你已经目睹了所有同事以不同方式死去。这一次——你选择直面这个掌控一切的人。",[{text:'【直接摊牌】"张总——我知道您得了早衰症。您需要QZ-酶的完美适配体——就是我。我们可以谈谈条件。"',next:[n("zz-s1-4a-n",'张总在原地站了整整十秒。然后——笑了。不是平时那种运筹帷幄的微笑。而是一个——疲惫的、自嘲的、几乎像是在说"终于"的笑。',"breakroom"),t("zz-s1-4a-d","张总","zhang","你知道多久了？","zhang",{affection:{zhang_trust:10}})],effects:{affection:{zhang_trust:10}}},{text:'【迂回试探】"我一直在想——如果一个人知道自己还剩多少时间，他会怎么度过剩下的日子？"',next:[t("zz-s1-4b-d","张总","zhang","（停下脚步——侧身——灰瞳在你脸上停留了三秒）这是一个——有趣的问题。但你不是来问哲学问题的。对吗？","zhang"),n("zz-s1-4b-n","他没有等你的回答。摘下右手手套——那只手比你在第3轮回中看到的更加衰老。他知道了。他一直在等你摊牌。","breakroom"),t("zz-s1-4b-d2","张总","zhang","既然你不愿意直接说——我替你说。我需要QZ-酶的完美适配体。而你——就是那个适配体。现在——我们谈谈条件。","zhang",{affection:{zhang_trust:5}})],effects:{affection:{zhang_trust:5}}},{text:'【继续装傻】"没什么。就是想多了解一下公司的项目。"',next:[t("zz-s1-4c-d","张总","zhang","（嘴角微不可察地弯了一下——像笑——又不像）是吗。那就继续了解吧。不过——你确定你没有别的话要对我说？","zhang"),n("zz-s1-4c-n","他转身准备离开。但你看到了——他的左手在微微颤抖。不是恐惧。是疾病。如果你现在不开口——可能永远没有机会了。","breakroom"),e("zz-s1-4c-ch","你看着他走向门口。背影——比你想的更孤独。",[{text:'【开口】"张总——等等。我有话要说。"',next:[n("zz-s1-4c-cha","他停住了。没有回头。但也没有继续走。","breakroom"),t("zz-s1-4c-cha-d","张总","zhang","我一直在等你说这句话。坐下吧。","zhang",{affection:{zhang_trust:5}})]},{text:"【沉默】让他走。",next:[n("zz-s1-4c-chb","门合上了。茶水间只剩下你一个人——和一杯凉掉的咖啡。有些事情——错过了就是错过了。","breakroom"),c("zz-s1-4c-chb-sys","张总离开了。隐藏线关闭。\n\n需要在下一次轮回中重新尝试。")]}])]}]),n("zz-cg-hands","他摘下手套的瞬间。那双隐藏了七次轮回的手——终于暴露在白炽灯下。皮肤上布满暗褐色老年斑。关节变形。指甲萎缩。不像45岁。像75岁。这是Werner综合征——也是他困在这个身体里最深的秘密。","breakroom"),n("zz-s1-5","他坐了下来——第一次在你面前摘下了手套。那双手——皮肤上布满暗褐色老年斑——关节变形——指甲萎缩——不像45岁。像75岁。","breakroom"),t("zz-s1-6","张总","zhang","Werner综合征变体。WRN基因突变。RecQ家族DNA解旋酶功能缺陷。WRN解旋酶负责解开DNA复制叉前方双链——没有它——复制叉停滞——双链断裂——基因组不稳定性以正常速度的一千倍累积。","zhang"),t("zz-s1-7","张总","zhang","我今年45岁。生物学年龄——大概72岁。我还有大约一年。如果不使用QZ-酶——一年。","zhang"),s("zz-s1-8","张总看着你——不像在看一个下属。像是在看一个——值得被认真对待的对手。",{question:"端粒酶在正常体细胞中不表达——但在哪些细胞中高表达？其催化亚基是什么？",options:[{label:"A",text:"干细胞、生殖细胞和约85-90%的肿瘤细胞——通过重新激活hTERT(端粒酶逆转录酶)表达维持端粒长度",correct:!0},{label:"B",text:"肝细胞和心肌细胞——通过hTERT维持端粒",correct:!1},{label:"C",text:"所有分裂细胞——端粒酶是细胞周期的必需组分",correct:!1},{label:"D",text:"红细胞和血小板——通过端粒酶维持无核细胞的寿命",correct:!1}],explanation:'端粒酶(hTERT+hTR)是特殊的逆转录酶——以自身RNA模板(hTR)合成端粒TTAGGG重复序列。正常体细胞中端粒酶被表观遗传沉默→端粒每次分裂缩短50-200bp→到达Hayflick极限(~50次分裂)→复制性衰老。干细胞和生殖细胞维持端粒酶活性以实现自我更新。约85-90%的肿瘤通过重新激活hTERT获得"无限增殖"能力——这是癌症的hallmark之一。Werner综合征中WRN解旋酶缺陷加速端粒损耗——使复制性衰老提前数十年到来。',knowledgeId:"telomerase_cancer",knowledgeTitle:"端粒酶——干细胞/生殖细胞/肿瘤的端粒维持与Hayflick极限"},[t("zz-s1-8c","张总","zhang","你确实做了功课。hTERT——端粒酶逆转录酶。没有它——端粒就像一根燃烧的引信。每次分裂——烧掉一截。烧完了——细胞就死了。我体内的这根引信——比正常人短得多。","zhang",{affection:{zhang_trust:8}}),n("zz-s1-8cn","他微微点头——眼神中闪过一丝罕见的认可。这是第一次——他把你当作可以对话的人，而不是实验对象。","breakroom")],[t("zz-s1-8w","张总","zhang",'干细胞。生殖细胞。肿瘤细胞。端粒酶让它们"永生"。正常体细胞——没有这个奢侈。我的WRN突变让情况更糟——端粒缩短的速度是正常人的三到五倍。',"zhang")]),s("zz-s1-9","张总将手平放在桌上。那双手在日光灯下——衰老的痕迹无可遁形。他调出手机上的基因表达谱芯片数据。",{question:"呼吸链中活性氧(ROS)主要在哪些复合体产生？机体如何清除ROS？",options:[{label:"A",text:"复合体I(FMN和铁硫簇处)和复合体III(Q循环中的泛醌自由基·Q⁻)；由SOD/CAT/GPx/GSH系统清除",correct:!0},{label:"B",text:"只在复合体IV(细胞色素c氧化酶)产生——由过氧化氢酶清除",correct:!1},{label:"C",text:"只在复合体V(ATP合酶)产生——由超氧化物歧化酶清除",correct:!1},{label:"D",text:"ROS对身体有益——不需要清除",correct:!1}],explanation:"电子传递链的主要ROS泄漏点：复合体I的FMN辅基和铁硫簇将电子泄漏给O₂→·O₂⁻(超氧阴离子)；复合体III的Q循环中泛醌自由基(·Q⁻)将电子捐赠给O₂→·O₂⁻。清除系统：SOD(超氧化物歧化酶，·O₂⁻→H₂O₂+O₂)、CAT(过氧化氢酶，2H₂O₂→2H₂O+O₂)、GPx(谷胱甘肽过氧化物酶)、GSH(还原型谷胱甘肽)。mtDNA比核DNA更易受氧化损伤——缺乏组蛋白保护且修复系统不完善——这是衰老自由基学说的核心。",knowledgeId:"ros_oxidative_stress",knowledgeTitle:"ROS产生与清除——衰老的自由基学说与线粒体氧化损伤"},[t("zz-s1-9c","张总","zhang","复合体I。FMN。铁硫簇。复合体III。Q循环。·Q⁻。这四个名字——描述了我体内正在发生的灾难。我体内的SOD和过氧化氢酶活性不到正常人的30%。氧化损伤像滚雪球——损伤越多→修复越耗能→ROS产生越多→损伤更多。恶性循环。","zhang",{affection:{zhang_trust:10}})],[t("zz-s1-9w","张总","zhang","复合体I和III。SOD。过氧化氢酶。谷胱甘肽。这四个词——描述了我正在失去的一切。","zhang")]),n("zz-s2-1","茶水间的气氛变了。不再是上司和下属的对峙——而是两个知道彼此底牌的人在谈判。张总双手交叉——那双衰老的手在日光灯下格外刺目。","breakroom"),t("zz-s2-2","张总","zhang","既然你把牌摊开了——我也摊开。我需要你——不是要杀你，不是要做实验。我需要你配合我完成至少50次完整轮回的数据记录。","zhang"),t("zz-s2-3","张总","zhang",'50次之后——DARPA会得到他们想要的"人类决策全图谱"。我拿到我的治疗数据。你——你可以走。带着你的同事一起走。我会确保公司被合规关闭——所有人的记录被清除。',"zhang"),t("zz-s2-4","张总","zhang","或者——你也可以选择留下来。和我一起。我死后——整个普罗米修斯——所有的数据、设备、资金——都是你的。你可以用它们做任何你想做的事。治疗罕见病。发《自然》和《科学》。获得诺贝尔奖。唯一的条件——完成轮回数据收集。","zhang"),e("zz-s2-5","他身体前倾。灰色眼瞳在屏幕反光中像是两盏快要熄灭的灯——但仍在燃烧。这是他第一次——向你展示选择。",[{text:'【答应合作】"50次轮回。然后我们两清。"',next:[t("zz-s2-5a","张总","zhang","（缓缓靠回椅背——嘴角闪过一个几乎看不见的微笑）好。50次。两清。你比你父亲——更务实。","zhang",{affection:{zhang_trust:15},flag:"zz_deal_cooperate"})],effects:{affection:{zhang_trust:15},flag:"zz_deal_cooperate"}},{text:'【假装答应——暗中破坏】"好。我配合你。"（内心：我要找到破绽——摧毁这一切）',next:[t("zz-s2-5b","张总","zhang","（盯着你看了五秒——像是读到了什么）你知道吗——你父亲当年也用同样的眼神看过我。好。我选择相信你。不要让我后悔。","zhang",{affection:{zhang_trust:5},flag:"zz_deal_double"}),n("zz-s2-5bn","他的眼神说——他知道你在想什么。但他选择了相信。或是选择了——赌。","breakroom")],effects:{affection:{zhang_trust:5},flag:"zz_deal_double"}},{text:'【拒绝】"我不会成为你的实验记录。"',next:[t("zz-s2-5c","张总","zhang","（沉默了很长时间——长到你几乎以为他要起身离开）你确定吗？这是你唯一一次——让我欠你的机会。","zhang"),n("zz-s2-5cn","空气凝固了。他的手在桌面上颤抖——不是因为愤怒。是因为疾病。如果你拒绝他——他会找到另一个方法。但那会是什么样的方法？","breakroom"),t("zz-s2-5c-d2","张总","zhang","我给你三天时间。三天后——如果你还是这个答案——我们就是敌人了。我不想要这个结果。但我也不会让任何人——阻止我活下去。","zhang",{affection:{zhang_trust:-10},flag:"zz_deal_refuse"})],effects:{flag:"zz_deal_refuse"}}]),n("zz-s3-1","B3层。比地下实验室更深的地方。张总用一把物理钥匙——不是门禁卡，不是虹膜识别——一把真正的铜质钥匙——打开了一扇你从未注意过的门。","b3_cryo"),n("zz-s3-2","房间不大。透射电子显微镜。PCR仪。液氮罐。离心机。和一张病床。病床上方的墙上钉满了MRI和CT扫描片——全都是同一个人的。全都是张总自己的。","b3_cryo"),t("zz-s3-3","张总","zhang","欢迎来到——我的世界。这间屋子里的每张片子都是我。动脉粥样硬化。骨质疏松。二型糖尿病。双侧白内障。早衰面容。Werner综合征患者该有的——我全有。","zhang_lab"),t("zz-s3-4","张总","zhang","WRN解旋酶——RecQ家族——负责解开DNA复制叉前方的双链。没有它——复制叉停滞——双链断裂——基因组崩溃。正常人的基因组修复系统能处理这些损伤。我的——处理速度跟不上损伤累积的速度。一千倍的差距。","zhang_lab"),n("zz-s3-5","他从液氮罐中取出一个冻存管。里面是组织样本——他自己的肝脏穿刺样本。每三个月取一次——已经连续取了八年。","b3_cryo"),t("zz-s3-6","张总","zhang","如果你把它们排成一排——你就看到衰老是什么了。","zhang_lab"),n("zz-s3-7",'显微镜屏幕上的图像序列依次显示：\n第1年：正常肝细胞，线粒体丰度正常，嵴结构清晰。\n第3年：少数肝细胞出现巨大线粒体——mtDNA突变→呼吸链缺陷→代偿性线粒体增大。\n第5年：约15%肝细胞细胞色素c氧化酶阴性——COX阴性——蓝色染色——复合体IV缺陷的经典标记。\n第7年：约40%肝细胞COX阴性。脂褐素——"衰老色素"——在细胞质中大量沉积。"老年斑"的细胞级版本。',"b3_cryo"),t("zz-s3-8","张总","zhang","看到了吗？我不是在变老——我是在被氧化。从内到外。线粒体——细胞的发电厂——正在变成细胞的火葬场。","zhang_lab"),s("zz-s3-9","张总调出另一组数据——mtDNA突变负荷与呼吸链复合体活性的相关性曲线。",{question:"为什么线粒体DNA(mtDNA)比核DNA更容易受到氧化损伤？mtDNA突变累积如何导致衰老？",options:[{label:"A",text:"mtDNA缺乏组蛋白保护、修复系统不完善、靠近ROS产生位点(呼吸链)；突变累积→呼吸链缺陷→更多ROS→更多突变→恶性循环→细胞能量代谢崩溃",correct:!0},{label:"B",text:"mtDNA比核DNA更稳定——不受氧化损伤",correct:!1},{label:"C",text:"mtDNA有特殊的组蛋白保护——比核DNA更耐氧化",correct:!1},{label:"D",text:"mtDNA突变不影响细胞功能——是无害的",correct:!1}],explanation:"mtDNA氧化损伤易感性三因素：①缺乏组蛋白保护——裸露的环状DNA直接暴露于基质中的ROS；②修复系统不完善——缺乏核苷酸切除修复(NER)途径，主要依赖碱基切除修复(BER)；③地理位置——紧邻呼吸链(ROS产生位点)，局部ROS浓度极高。突变累积→呼吸链复合体(尤其复合体I和IV)功能缺陷→电子泄漏增加→更多ROS→更多mtDNA突变→正反馈恶性循环。这是衰老的线粒体自由基学说核心——也是张总体内正在加速上演的灾难。",knowledgeId:"mtDNA_mutation_aging",knowledgeTitle:"mtDNA突变累积——线粒体自由基衰老理论的分子基础"},[t("zz-s3-9c","张总","zhang","组蛋白。修复系统。地理位置。三重不幸——全压在线粒体DNA上。我的mtDNA突变负荷是同龄人的二十倍。二十倍。你知道这意味着什么——每一个细胞都在以二十倍的速度走向崩溃。","zhang_lab",{affection:{zhang_trust:10}})],[t("zz-s3-9w","张总","zhang","没有组蛋白。没有完善的修复。紧挨着ROS的源头。线粒体DNA——从设计上就是一个美丽的错误。","zhang_lab")]),n("zz-s3-10","张总在另一个屏幕上调出了QZ-酶的数据——在有你DNA存在时的活性变化曲线。那条曲线——在主角DNA存在时——陡然上升。","b3_cryo"),t("zz-s3-11","张总","zhang",'QZ-酶——在你DNA存在下——可以在线粒体中替代缺陷型呼吸链复合体的功能。它填补了WRN解旋酶缺失造成的链断裂修复缺陷。它重新连接断裂的电子传递。它不是"永生之药"——它只是让我能活到我应该活的年龄。45岁。不是72岁的生物学年龄。45岁。',"zhang_lab"),n("zz-s3-12","他第一次转过身来正对你。灰色眼瞳在屏幕的反光中像是两盏快要熄灭的灯——但在那快要熄灭的光里，你看到了别的东西。","b3_cryo"),t("zz-s3-13","张总","zhang",'你知道知道自己的死期意味着什么吗？不是恐惧——恐惧会过去。是孤独。你站在所有人中间——但你知道你会在他们之前离开。你的每一次"再见"——本质上可能都是"永别"。我不怕死。我怕的是——没有人会记得我。',"zhang_lab",{affection:{zhang_trust:15}}),n("zz-s3-14",'他害怕的——是无意义。他穷尽一生追求"留下什么"——害怕自己像一根燃烧完的蜡烛，连烟都不会被看见。',"b3_cryo"),n("zz-s4-1","几天后。张总的病情突然恶化——不是因为早衰症本身——而是因为他体内累积的mtDNA突变已经触发了多个组织的细胞凋亡信号。","b3_cryo"),n("zz-s4-2","你扶着几乎站不住的张总坐到病床上。他大汗淋漓——嘴唇发绀——但眼睛还是亮的。那种亮——不是希望——是执念。","b3_cryo"),t("zz-s4-3","张总","zhang","细胞凋亡——程序性细胞死亡——不是坏死。坏死是事故——细胞肿胀破裂——内容物泄漏——引发炎症。凋亡——是调度。是命令。是细胞自己选择去死。","zhang_lab"),t("zz-s4-4","张总","zhang","线粒体外膜通透性改变→释放细胞色素c→结合Apaf-1→募集caspase-9→形成凋亡体→激活下游执行caspase-3→切割细胞骨架蛋白和DNA修复酶PARP→DNA断裂成180bp的整数倍片段→细胞有秩序地解体→形成凋亡小体→巨噬细胞吞噬清理——干干净净。","zhang_lab"),t("zz-s4-5","张总","zhang","这就是为什么衰老不会痛。细胞是一个一个死的——不是一起死的。直到——关键器官的细胞数量跌破功能阈值——然后——死亡。我现在——正在感受这个过程。每一个正在凋亡的肝细胞——都在告诉我——时间快到了。","zhang_lab"),s("zz-s4-6","他说话的声音越来越弱——但每一个术语的发音依然精准。像是在讲课。又像是在说服自己。",{question:"Bcl-2家族在调控线粒体凋亡途径中至关重要。促凋亡和抗凋亡成员分别有哪些？其作用机制是什么？",options:[{label:"A",text:"促凋亡：Bax、Bak(在线粒体外膜形成孔道释放细胞色素c)；抗凋亡：Bcl-2、Bcl-xL(与Bax/Bak形成异源二聚体阻止成孔)",correct:!0},{label:"B",text:"所有Bcl-2家族成员都是抗凋亡的",correct:!1},{label:"C",text:"所有Bcl-2家族成员都是促凋亡的",correct:!1},{label:"D",text:"只有Bcl-2有功能——其他成员是假基因",correct:!1}],explanation:"Bcl-2家族是凋亡线粒体途径的核心调控者。促凋亡成员(Bax/Bak)在线粒体外膜寡聚化形成孔道→线粒体外膜通透化(MOMP)→释放细胞色素c和Smac/DIABLO。抗凋亡成员(Bcl-2/Bcl-xL/Mcl-1)通过与Bax/Bak形成异源二聚体阻止其成孔。二者的表达比例决定细胞生死。BH3-only蛋白(Bid/Bim/Puma等)感知凋亡信号并激活Bax/Bak或抑制Bcl-2。在多种癌症中Bcl-2过表达→癌细胞逃避凋亡——Bcl-2抑制剂Venetoclax是靶向抗癌药。",knowledgeId:"bcl2_apoptosis",knowledgeTitle:"Bcl-2家族——线粒体凋亡途径的分子闸门"},[t("zz-s4-6c","张总","zhang","Bax。Bak。Bcl-2。Bcl-xL。四种蛋白——决定了我体内每一个细胞的生死。而现在——我的Bax和Bak正在获胜。系统性地。不可逆地。","zhang_lab",{affection:{zhang_trust:10}})],[t("zz-s4-6w","张总","zhang","Bax和Bak——促凋亡——在线粒体外膜打孔。Bcl-2和Bcl-xL——抗凋亡——堵住那些孔。两者之间的平衡——就是生与死的平衡。我的平衡——正在崩溃。","zhang_lab")]),n("zz-s4-7","他突然紧抓住你的手腕。那力气——完全不像一个垂死的人。","b3_cryo"),t("zz-s4-8","张总","zhang","林墨——如果我停止呼吸——不要打120。我签了DNR——不复苏意愿——在我的办公室抽屉里。让我死。让我死得有尊严。","zhang_lab"),t("zz-s4-9","张总","zhang","我在ICU里见过太多——肋骨被按断——气管被切开——身体被机器接管——意识却早已不在。那不是活着。那是——被活着。我不要那个。","zhang_lab"),n("zz-s5-1","他从床头柜的暗格中取出一个银色小盒。打开——里面是一支微型注射器。深绿色的液体在其中微微发光。","b3_cryo"),t("zz-s5-2","张总","zhang","这是QZ-酶的精制样本。纯度——99.97%。活性是发酵罐里那个粗提物的370倍。我花了八年纯化它——从我自己的组织里——一微克一微克地。","zhang_lab"),t("zz-s5-3","张总","zhang","给我注射。让我——至少死之前——能有最后一次轮回。我想回去——回到我妻子还在的时候——哪怕只是几天。哪怕只是——再看她一眼。","zhang_lab"),n("zz-s5-4","他的声音——几十年来第一次——碎了。不是那个运筹帷幄的CEO。不是那个冷血的实验者。是一个——想念妻子的丈夫。","b3_cryo"),t("zz-s5-5","张总","zhang","她叫苏婉。婚后第三年——诊断出晚期卵巢癌。我当时已经是生化博士后——但什么都做不了。她从一个健康的人——到离开——只用了——一个月。","zhang_lab",{affection:{zhang_trust:20}}),t("zz-s5-6","张总","zhang",'那是一个月——不是三十天——是每一天。每一天她都少一点。每一天她的眼睛都更远一点。最后一天——她问我——"启明——我的病——你是不是早就知道治不好？"我说——"不知道。"那是——我这辈子说的最痛苦的一句谎话。',"zhang_lab",{affection:{zhang_trust:20}}),n("zz-s5-7","他握着注射器的手——那双布满老年斑、关节变形的手——在颤抖。不是因为虚弱。是因为——这是他和过去之间——最后一座桥。","b3_cryo"),e("zz-s5-8","注射器就在你面前。深绿色的液体在微型注射器中微微发光。这是纯度99.97%的QZ-酶——活性是发酵罐粗提物的370倍。他想回到妻子还在的时候——哪怕只是几天。",[{text:"【给他注射】满足他最后的愿望。",next:[n("zz-s5-8a-n","你接过注射器。他的皮肤很薄——几乎能看到下面的静脉。针头刺入皮肤的时候——他没有看针——他看的是远处。某个——只有他能看到的地方。","b3_cryo"),t("zz-s5-8a-d","张总","zhang","（深绿色液体缓缓推入静脉——他的瞳孔短暂放大——然后身体开始抽搐）……苏婉……我……来了……","zhang_lab"),n("zz-s5-8a-n2","但QZ-酶没有触发轮回。他的端粒太短。mtDNA突变太多。时间戳写入失败。轮回——无法启动。\n\n他死在病床上。脸上的表情——像是解脱。","b3_cryo")],effects:{affection:{zhang_trust:30},flag:"zz_injected"}},{text:'【拒绝】"我不能。你已经活得够久了——比别人多活了二十年。够了。"',next:[t("zz-s5-8b-d","张总","zhang","（注射器从他手中滑落——滚到地上——没有碎——只是滚到了墙角）二十年——是偷来的。每一天——都是偷来的。你说得对——够了。","zhang_lab"),n("zz-s5-8b-n","他闭上眼睛。眼角有一道微光——不是眼泪——是这个房间里LED屏幕的反光。他即将死在这个属于他自己的、堆满了数据的房间里。没有人会知道。除了你。","b3_cryo"),t("zz-s5-8b-d2","张总","zhang","（声音越来越轻——像是在对自己说）如果当年——我拦住DARPA——拦住我自己——拦住一切——远山还会活着。苏婉——当然不会——但至少——远山还会活着。","zhang_lab",{flag:"zz_refused"})],effects:{flag:"zz_refused"}},{text:'【给自己注射】"你研究了这么久——让我来帮你验证最后的数据。"',next:[n("zz-s5-8c-n","你抢过注射器——在他震惊的眼神中——将深绿色的液体推入了自己的静脉。冰冷的感觉从手臂蔓延到全身。世界开始旋转。","b3_cryo"),t("zz-s5-8c-d","张总","zhang","（瞪大了眼睛——几十年来第一次——他看起来像一个真正的45岁的人——因为震惊——不是衰老）你疯了——你疯了！那是给一个快死的人用的——不是给你——","zhang_lab"),n("zz-s5-8c-n2","你的意识开始模糊。在边缘——你看到了什么。不是回忆——是轮回。你自己的轮回。张总的数据——所有的数据——正在以你无法理解的方式——写入你的意识。\n\n你成为了——新的宿主。","b3_cryo")],effects:{affection:{zhang_trust:50},flag:"zz_self_inject",san:-20}}]),n("zz-s6-1","张总生命的最后时刻。他从保险箱底层取出一封泛黄的信——不是数据文件——是一封真正的手写信。纸已经发脆。折痕已经快要断裂。","b3_cryo"),t("zz-s6-2","张总","zhang",'你父亲把QZ-酶的核心数据分成了五个碎片。他在设计保护性多肽的时候——做了两个版本。第一个版本——"停下一切"——一种别构抑制剂，结合在酶的调节位点，使酶完全失活。你父亲不喜欢。他说这不是保护——是囚禁。所以他做了第二个版本。',"zhang_lab",{affection:{zhang_trust:15}}),s("zz-s6-3","张总调出QZ-酶活性中心的3D结构——包括他之前故意隐藏的别构位点构象。",{question:"酶的活性中心与别构位点有何区别？基于结构的药物设计中——别构抑制剂相对于活性中心竞争性抑制剂有什么优势？",options:[{label:"A",text:"活性中心催化反应，别构位点调控酶构象(R态/T态)；别构抑制剂选择性更高——因为别构位点在不同酶间保守性低于活性中心——可减少脱靶效应",correct:!0},{label:"B",text:"活性中心和别构位点没有区别——都是底物结合位点",correct:!1},{label:"C",text:"别构抑制剂总是比活性中心抑制剂更弱——没有临床价值",correct:!1},{label:"D",text:"活性中心只能结合抑制剂——别构位点只能结合激活剂",correct:!1}],explanation:'活性中心(active site)是酶催化底物转化的区域——结合底物并稳定过渡态。别构位点(allosteric site)是远离活性中心的调控位点——结合别构效应物后通过构象变化(T态↔R态)调节酶的催化活性。别构抑制剂相对于正构(活性中心)抑制剂的优势：①选择性更高——别构位点在不同酶(甚至同一家族)间保守性低于活性中心；②不完全阻断——不竞争底物结合——保留了酶的生理调控空间；③可调节性——效应物浓度变化可以精细调控酶活性。张总提到的"第一个版本"就是结合别构位点使QZ-酶锁定在T态(紧张态/低活性)——"囚禁"它。第二个版本则保留了构象切换能力。',knowledgeId:"enzyme_allostery_structure",knowledgeTitle:"酶的活性中心与别构调控——基于结构的药物设计原理"},[t("zz-s6-3c","张总","zhang","对。正构抑制——堵死活性中心——无差别阻断。别构抑制——在别处施加影响——通过构象变化间接调控。第一个版本是别构锁定——把QZ-酶锁死在T态。你父亲说那是囚禁。他选了第二个版本——可逆的、可调控的。他永远——选择自由。","zhang_lab",{affection:{zhang_trust:15}})],[t("zz-s6-3w","张总","zhang","活性中心——催化。别构位点——调控。一个在中心——一个在边缘。但有时候——边缘的影响力——不亚于中心。我用了二十五年才明白这个道理。","zhang_lab")]),n("zz-s6-4","他递过那封信。纸张泛黄——边缘已磨损——但字迹依然清晰。","b3_cryo"),n("zz-s6-5",'信的内容很简单——写于张总的婚礼当天：\n\n"启明：\n不管发生什么——我相信你心里的那个好人还在。\n酶没有善恶。是使用它的人——决定了它是毒药还是良药。\n你的师兄，远山\n1998年6月12日"',"b3_cryo"),t("zz-s6-6","张总","zhang","二十五年。这封信——我放在保险箱最底层——压在DARPA合同、经费审批、实验数据——所有东西下面。但我从来没有扔掉它。从来没有。","zhang_lab",{affection:{zhang_trust:20}}),t("zz-s6-7","张总","zhang",'远山——你父亲——他知道我是什么样的人。他知道我有野心——知道我不安分——知道我会做很多不应该做的事。但他还是写了这封信。他选择相信那个"好人"——在我自己都不相信的时候。',"zhang_lab",{affection:{zhang_trust:20}}),n("zz-s6-8","他的声音顿了顿。窗外没有阳光——B3层没有窗户——但屏幕的冷光打在泛黄的信纸上。","b3_cryo"),t("zz-s6-9","张总","zhang","那个好人——一直都在。只是被我锁在了一个——太深的地方。锁了二十五年。当我终于想把他放出来的时候——我已经没有时间了。","zhang_lab",{affection:{zhang_trust:25}}),n("zz-s7-1","他咳了一阵——手帕上出现了血迹。但他还是继续说了下去。像是在完成人生最后一个任务。","b3_cryo"),t("zz-s7-2","张总","zhang","林墨——我要告诉你一件事。关于你父亲的死。你以为是车祸——所有人都以为是车祸。但不是。是DARPA。是你父亲的师兄——是我——张启明——没有阻止。","zhang_lab"),t("zz-s7-3","张总","zhang",'远山拒绝交出QZ-酶数据后——DARPA决定"清除"他。我收到了通知——事前通知。我可以警告他——让他跑——让他躲——但我没有。我告诉自己——他是我的竞争对手——他挡了我的路——但实际上——我在恐惧。恐惧他会阻止我得到QZ-酶——阻止我活下去。恐惧让我选择了沉默——沉默让我成为了同谋。',"zhang_lab",{affection:{zhang_trust:10}}),t("zz-s7-4","张总","zhang","那个决定——是我人生最大的错误。也是我——永远无法弥补的错误。这几年——我一直在偷偷资助你母亲的医疗费用。匿名转账。不是赎罪——赎不了的。是——我想让她至少——过得稍微好一点。这是我唯一能做的补偿。","zhang_lab"),n("zz-s7-5","他的声音完全变了。不是CEO在下命令。不是科学家在讲数据。是一个背负了二十五年罪孽的人——在死前——终于承认。","b3_cryo"),n("zz-s7-6","他从终端中调出最后一份数据——QZ-酶活性中心的完整结构——包括之前故意隐藏的别构位点构象和反向抑制酶的设计模板。","b3_cryo"),t("zz-s7-7","张总","zhang","这些——是我之前不给你看的数据。我之前不给你——是因为我想控制你。现在我快死了——控制已经没有意义了。全部都在这里。QZ-酶活性中心。别构位点构象。反向抑制酶的设计模板。和——总控密钥。","zhang_lab",{affection:{zhang_trust:25}}),n("zz-s7-8","他从口袋中取出一个物理U盘——不是云端传输——是实实在在的、能被握在手心里的数据。抵到你面前。","b3_cryo"),t("zz-s7-9","张总","zhang","拿着。反向抑制酶的设计模板——可以让你制造出能关闭QZ-酶的抑制剂。如果有一天——DARPA或者后来者——想要用QZ-酶做不该做的事——你可以阻止他们。这是——我可以做的——最后一件正确的事。","zhang_lab",{affection:{zhang_trust:30}}),n("zz-s7-10","你接过U盘。他的手——那双衰老的、布满老年斑的手——在碰到你的那一刻——短暂地停留了一秒。像是在传递什么——比数据更重的东西。","b3_cryo"),t("zz-s7-11","张总","zhang","林墨——你父亲是对的。酶没有善恶。是使用它的人——决定了它是毒药还是良药。我选了毒药的路——选了二十五年。现在——我把选择交给你。","zhang_lab",{affection:{zhang_trust:30}}),n("zz-s8-1","他的呼吸越来越浅。心率监测器的声音——从规律变为断续。但他在笑。那笑容——和35岁时的他——一模一样。","b3_cryo"),t("zz-s8-2","张总","zhang","我本来以为——我是一个坏人——被命运变成了反派。现在我明白了——我只是一个害怕的人——被恐惧变成了怪物。不一样的选择——你还是你——我还是我吗？","zhang_lab"),t("zz-s8-3","张总","zhang","或许那根本不重要。重要的是——你还有选择。而我——已经选完了。","zhang_lab"),n("zz-s8-4","监测器发出长鸣。窗外没有阳光——B3层没有窗户。但不知为何——他的脸上——在黑暗的实验室里——看起来像是在阳光中。","b3_cryo"),n("zz-s8-5","那个曾经意气风发的35岁年轻CEO——已经在生物学上85岁了。只有他嘴角最后一次扬起的弧度——看起来像35岁的他。","b3_cryo"),c("zz-end",'张总隐藏线结局触发条件：\n\n━━━━━━━━━━━━━━━━━━━━━━━━\n★ E01-ZZ 真结局「第六人的微笑」\n   条件：信任值40-60 + 答题正确率≥85% + 轮回≥7次\n        + 选择给他注射 + 选择了直接摊牌\n   → 获得总控密钥+完整数据+反向抑制酶设计\n   → 真结局前置条件解锁\n\n★ E07-ZZ 彩蛋结局「酶学大师」\n   条件：所有生化知识答题满分 + 回避所有恋爱选项\n        + 展现了无可挑剔的学术水平\n   → 张总修改遗嘱——匿名捐赠哈佛MIT联合研究所\n   → 林墨获诺贝尔奖\n\n★ E03-ZZ BE「霸道总裁的棋子」\n   条件：全程顺从张总 + 告发所有同事 + 好感度一面倒\n        + 信任值>60（被他"收藏"）\n   → 张总获得永生雏形——林墨被关进低温舱\n   → 成为"备用的活性酶来源"\n\n★ E04-ZZ BE「拒绝的代价」\n   条件：拒绝注射 + 信任值<-20\n   → 张总在绝望中死去——关键数据未解锁\n\n★ E05-ZZ NE「西西弗斯的轮回」\n   条件：给自己注射QZ-酶\n   → 你成为新的数据宿主——轮回继续——但方向未知')])}}});